function zhNewsBody(lang) {
  var cards = ZH_NEWS_CARDS.map(function(n, i){
    var imgStyle = (i === 2 || i === 4) ? ' style="object-position:top center;"' : '';
    return '<a href="'+n.url+'" target="_blank" rel="noopener" class="zh-news-card">'
      +'<div class="zh-news-img-wrap"><img src="'+n.img+'" alt="news" loading="lazy"'+imgStyle+'></div>'
      +'<div class="zh-news-text">'
      +'<div class="zh-news-title">'+(n.title[lang]||n.title.kk)+'</div>'
      +'<div class="zh-news-desc">'+(n.desc[lang]||n.desc.kk)+'</div>'
      +'</div>'
      +'</a>';
  }).join('');
  return '<style>'
    +'.zh-news-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:22px;padding:4px 0;}'
    +'.zh-news-card{display:block;text-decoration:none;border-radius:14px;overflow:hidden;box-shadow:0 2px 14px rgba(0,0,0,.10);background:#fff;transition:transform .22s,box-shadow .22s;cursor:pointer;}'
    +'.zh-news-card:hover{transform:translateY(-6px);box-shadow:0 10px 32px rgba(184,144,90,.22);}'
    +'.zh-news-img-wrap{width:100%;height:190px;overflow:hidden;background:#f5ead8;}'
    +'.zh-news-img-wrap img{width:100%;height:100%;object-fit:cover;display:block;transition:transform .3s;}'
    +'.zh-news-card:hover .zh-news-img-wrap img{transform:scale(1.05);}'
    +'.zh-news-text{padding:14px 16px 16px;}'
    +'.zh-news-title{font-size:14px;font-weight:700;color:#2c1e0e;line-height:1.4;margin-bottom:6px;}'
    +'.zh-news-desc{font-size:12.5px;color:#6b5a45;line-height:1.5;}'
    +'@media(max-width:600px){.zh-news-grid{grid-template-columns:1fr;}}'
    +'</style>'
    +'<div class="zh-news-grid">'+cards+'</div>';
}

window.zhStaticPage = function(key) {
  var lang = zhLang();
  var data = ZH_STATIC[key];
  if (!data) return;
  var d = data[lang] || data['ru'];
  var root = document.getElementById('root');

  // For news page, use dynamic body
  if (key === 'news') {
    d = Object.assign({}, d, { body: (typeof zhNewsBody === 'function') ? zhNewsBody(lang) : '' });
  }
  var page = root.querySelector('.page');
  if (page) {
    var tabContent = document.getElementById('tabContent');
    if (tabContent) {
      var tabBar = document.getElementById('_zh_tabbar_hidden');
      if(tabBar) tabBar.style.display = 'none';

      tabContent.innerHTML =
        '<div style="animation:fadeInUp .3s ease;">' +
          '<h2 style="font-family:\'Inter\',sans-serif;font-size:22px;font-weight:900;color:var(--g1);margin-bottom:16px;">' + d.title + '</h2>' +
          '<div class="card" style="padding:24px 28px;">' + d.body + '</div>' +
          '<button onclick="zhBackToDashboard()" style="margin-top:18px;padding:9px 24px;border-radius:50px;border:2px solid var(--g1);background:transparent;color:var(--g1);font-size:13px;font-weight:700;cursor:pointer;font-family:\'Inter\',sans-serif;transition:all .2s;">' +
            '← ' + (lang==='kk'?'Артқа':lang==='en'?'Back':'Назад') +
          '</button>' +
        '</div>';
      return;
    }
  }

  // Fallback: full page replace
  root.innerHTML =
    '<div class="zh-static-page">' +
      '<h2>' + d.title + '</h2>' +
      '<div class="card">' + d.body + '</div>' +
      '<button class="zh-back" onclick="zhBackToDashboard()">← ' + (lang==='kk'?'Артқа':lang==='en'?'Back':'Назад') + '</button>' +
    '</div>';
};

/* ─── TAB SWITCHER ─── */
// Tab order in app.js TABS array (0-indexed):
// 0=plan, 1=clinics_all, 2=gov_support, 3=inspire, 4=games, 5=ai, 6=law, 7=charity
var ZH_TAB_IDX = { plan:0, clinics_all:1, gov_support:2, inspire:3, games:4, ai:5, law:6, charity:7 };

window.zhSwitchTab = function(id, subFilter) {
  var page = document.querySelector('#root .page');
  if (!page) {
    zhBackToDashboard();
    setTimeout(function(){window.zhSwitchTab(id, subFilter);}, 420);
    return;
  }

  var idx = ZH_TAB_IDX[id];
  var tabBtns = document.querySelectorAll('#root .tab-btn');
  if (idx !== undefined && tabBtns[idx]) {
    tabBtns[idx].click();
    // If a sub-filter was requested (e.g. 'abroad' inside clinics_all), activate it after render
    if (subFilter) {
      setTimeout(function(){
        // Find filter button whose label contains the subFilter keyword
        var filterBtns = document.querySelectorAll('#tabContent button');
        filterBtns.forEach(function(b){
          var txt = (b.textContent || '').toLowerCase();
          if (txt.indexOf(subFilter.toLowerCase()) !== -1 ||
              (subFilter === 'abroad' && (txt.indexOf('шетел') !== -1 || txt.indexOf('рубеж') !== -1 || txt.indexOf('abroad') !== -1))) {
            b.click();
          }
        });
      }, 120);
    }
    setTimeout(function(){
      var content = document.getElementById('tabContent');
      if (content) content.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 150);
  }
};

/* ─── NAVIGATE TO KAZAKHSTAN MAP ─── */
